let allData = {{workflowparams:allData}};
const updatedGD = [];
const saveAs = {{workflowparams:saveAs}};
const isForceComplete = {{workflowparams:isForceComplete}};
const pickingSetup = {{node:get_node_iFPuvJX2.data.data}};
const pageStatus = {{workflowparams:pageStatus}}

// Track invalid rows for reporting
const skippedRows = [];

if (pickingSetup?.picking_mode === "Auto" && saveAs !== "Cancelled") {
  const tableGD = {{node:code_node_ymugKpln.data.tableGD}}
  if (tableGD?.length > 0) {
    allData.table_gd = tableGD
  }
}

for (const [index, gdLineItem] of allData.table_gd.entries()) {
  if (!gdLineItem.gd_qty || gdLineItem.gd_qty === 0) {
    continue;
  }

  // ============================================================================
  // PRECAUTION: Skip if gd_qty > 0 but temp_qty_data is empty
  // This prevents invalid state where quantity exists without allocation
  // ============================================================================
  const tempQtyData = gdLineItem.temp_qty_data;
  const isEmpty =
    !tempQtyData ||
    tempQtyData === "" ||
    tempQtyData === "[]" ||
    tempQtyData === null;

  if (isEmpty) {
    skippedRows.push({
      index: index,
      material_code: gdLineItem.material_code || "Unknown",
      material_name: gdLineItem.material_name || "Unknown",
      gd_qty: gdLineItem.gd_qty,
      so_no: gdLineItem.so_no || "",
    });
    continue;
  }

  gdLineItem.customer_id = allData.customer_name || null;
  gdLineItem.organization_id = allData.organization_id;
  gdLineItem.plant_id = allData.plant_id || null;
  gdLineItem.billing_state_id = allData.billing_address_state || null;
  gdLineItem.billing_country_id = allData.billing_address_country || null;
  gdLineItem.shipping_state_id = allData.shipping_address_state || null;
  gdLineItem.shipping_country_id = allData.shipping_address_country || null;
  gdLineItem.assigned_to = allData.assigned_to || null;
  gdLineItem.line_index = index + 1;

  if (isForceComplete === "Yes") {
    gdLineItem.picking_status = "Completed";
  } else if (saveAs === "Cancelled") {
    gdLineItem.picking_status = gdLineItem.picking_status ? "Cancelled" : null;
  }

  if (
    pickingSetup &&
    !allData.picking_status &&
    saveAs === "Created" &&
    pageStatus === "Add" &&
    pickingSetup.picking_required === 1
  ) {
    if (pickingSetup.auto_trigger_to === 1) {
      gdLineItem.picking_status = "Created";
    } else {
      gdLineItem.picking_status = "Not Created";
    }
  }

  updatedGD.push(gdLineItem);
}

allData.table_gd = updatedGD;

if ({{workflowparams:pageStatus}} === "Add") {
  allData.gd_status = "Draft";
}

if (saveAs !== "Cancelled") {
  if (saveAs === "Draft") {
    if (
      allData.delivery_no_type !== -9999 &&
      (!allData.delivery_no ||
        allData.delivery_no === null ||
        allData.delivery_no === "")
    ) {
      allData.delivery_no = "draft";
    }
  } else {
    if (
      allData.delivery_no_type !== -9999 &&
      (!allData.delivery_no ||
        allData.delivery_no === null ||
        allData.delivery_no === "" ||
        allData.gd_status === "Draft")
    ) {
      allData.delivery_no = "issued";
    }
  }
}

let needCL;

if (allData.acc_integration_type !== "No Accounting" && {{workflowparams:needCL}} === "required") {
  needCL = "required";
} else {
  needCL = "not required";
}

if (isForceComplete === "Yes") {
  allData.picking_status = "Completed"
}

if (saveAs === "Cancelled") {
  allData.picking_status = allData.picking_status ? "Cancelled" : null;
}

let needSOCleanUp = 0

if (allData.gd_status === "Created") {
  const originalGD = {{node:get_node_xTRvHWB8.data.data}};

  // Match by so_line_item_id instead of index
  allData.table_gd.forEach((item) => {
    const originalItem = originalGD.table_gd?.find(
      orig => orig.so_line_item_id === item.so_line_item_id
    );
    if (originalItem) {
      item.prev_temp_qty_data = originalItem.temp_qty_data;
    }
  });

  if (allData.table_gd.length !== originalGD.table_gd.length) {
    needSOCleanUp = 1
  }
}

// Build validation report
let invalidData = 0;
let invalidDataMessage = "";

if (skippedRows.length > 0) {
  invalidData = 1;

  const rowDetails = skippedRows.map(row => 
    `Row ${row.index + 1}: ${row.material_code} (${row.material_name}) - qty: ${row.gd_qty}${row.so_no ? ` [SO: ${row.so_no}]` : ""}`
  ).join("\n");

  invalidDataMessage = `Warning: ${skippedRows.length} row(s) skipped due to missing allocation data (gd_qty > 0 but temp_qty_data empty):\n\n${rowDetails}\n\nThese rows may need manual allocation or the allocation workflow may have failed.`;
}

return {
  allData: allData,
  gd_status: allData.gd_status,
  needCL: needCL,
  picking_status: allData.picking_status === "" ? null : allData.picking_status,
  packing_status: allData.packing_status,
  needSOCleanUp: needSOCleanUp,
  invalidData: invalidData,
  invalidDataMessage: invalidDataMessage
};

return {
  required_fields: JSON.stringify([
    { name: "customer_name", label: "Customer" },
    { name: "plant_id", label: "Plant" },
    { name: "so_id", label: "Sales Order" },
    { name: "delivery_date", label: "Delivery Date" },
    { name: "delivery_no", label: "Goods Delivery Number" },
    {
        name: "table_gd",
        label: "Item Table",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
    },
]),
  data: JSON.stringify({
    customer_name: {{node:code_node_IyJHrBst.data.allData.customer_name}},
    plant_id: {{node:code_node_IyJHrBst.data.allData.plant_id}},
    so_id: {{node:code_node_IyJHrBst.data.allData.so_id}},
    delivery_date: {{node:code_node_IyJHrBst.data.allData.delivery_date}},
    delivery_no: {{node:code_node_IyJHrBst.data.allData.delivery_no}},
    table_gd: {{node:code_node_IyJHrBst.data.allData.table_gd}}
  })
}

